import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const f=JSON.parse('{"title":"新加坡货币兑换","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"transfers-and-fx/sg-fx.md","filePath":"zh-CN/transfers-and-fx/sg-fx.md"}'),o={name:"transfers-and-fx/sg-fx.md"};function l(i,a,n,h,s,p){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="新加坡货币兑换" tabindex="-1">新加坡货币兑换 <a class="header-anchor" href="#新加坡货币兑换" aria-label="Permalink to &quot;新加坡货币兑换&quot;">​</a></h1><p>货币兑换是指多种货币之间的相互转换。长桥新加坡提供货币兑换功能，方便交易新加坡股票、香港股票和美国股票。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>新加坡元（SGD）、港元（HKD）、美元（USD）、离岸人民币（CNH）</p><p>兑换方向：</p><table tabindex="0"><thead><tr><th>来源币种</th><th>可兑换为</th></tr></thead><tbody><tr><td>新加坡元（SGD）</td><td>美元（USD）、港元（HKD）</td></tr><tr><td>美元（USD）</td><td>新加坡元（SGD）、港元（HKD）</td></tr><tr><td>港元（HKD）</td><td>新加坡元（SGD）、美元（USD）</td></tr><tr><td>离岸人民币（CNH）</td><td>新加坡元（SGD）<strong>仅此一种</strong></td></tr></tbody></table><p>注意：CNH 只能兑换为 SGD，不支持兑换 USD 或 HKD。</p><h2 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h2><p>免费（不收取手续费）</p><h2 id="兑换汇率" tabindex="-1">兑换汇率 <a class="header-anchor" href="#兑换汇率" aria-label="Permalink to &quot;兑换汇率&quot;">​</a></h2><p>由银行供应商提供的实时汇率，以实际兑换时的汇率为准。</p><p>注意：频繁兑入兑出会存在汇率差。</p><h2 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h2><p>全年 7×24 小时。如系统长时间未响应导致兑换未完成，请联系客服协助处理。</p><h2 id="汇率" tabindex="-1">汇率 <a class="header-anchor" href="#汇率" aria-label="Permalink to &quot;汇率&quot;">​</a></h2><p>页面显示参考汇率，约每 60 秒自动更新一次，实际兑换金额以最终成交为准。</p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 货币兑换，查看当前参考汇率，输入金额后即可兑换。</p><h2 id="精度、用途限制与密码要求" tabindex="-1">精度、用途限制与密码要求 <a class="header-anchor" href="#精度、用途限制与密码要求" aria-label="Permalink to &quot;精度、用途限制与密码要求&quot;">​</a></h2><ul><li>兑换金额均四舍五入取整至小数点后两位</li><li>货币兑换功能仅用于交易结算，请勿用于货币投机，与交易无关的请求将被拒绝</li><li>提交兑换申请时需输入长桥<strong>交易密码</strong>（6 位数字）</li></ul>',20)])])}const u=t(o,[["render",l]]);export{f as __pageData,u as default};
